1	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
2	const LOYALTY_DISCOUNT_RATE = 0.2;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const PROCESSING_FEE = 5;
6	
7	const BASE_PREMIUM: Record<string, number> = {
8	  sword: 100,
9	  potion: 40,
10	  amulet: 60,
11	};
12	
13	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
14	
15	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
16	
17	const sumSurcharge = (items: Item[], appliesTo: (item: Item) => boolean, rate: number): number =>
18	  items.reduce((sum, item) => sum + (appliesTo(item) ? itemBasePremium(item) * rate : 0), 0);
19	
20	export function quote(customer: { yearsWithMHPCO: number }, items: Item[], contractIndex: number): number {
21	  const basePremium = items.reduce((sum, item) => sum + itemBasePremium(item), 0);
22	  const cursedSurcharge = sumSurcharge(items, (item) => item.cursed, CURSED_SURCHARGE_RATE);
23	  const enchantmentSurcharge = sumSurcharge(items, (item) => item.enchantment >= 5, HIGH_ENCHANTMENT_SURCHARGE_RATE);
24	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
25	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
26	  return basePremium + cursedSurcharge + enchantmentSurcharge + firstInsuranceSurcharge - loyaltyDiscount + PROCESSING_FEE;
27	}
28	
29	export function claim() {
30	  return undefined;
31	}
